#include <stdio.h>
#include <ctype.h>
#include <string.h>

int isPalindrome(char *str) {
    int start = 0;
    int end = strlen(str) - 1;
    while (start < end) {
        // Skip non-alphanumeric characters from the start
        while (!isalnum(str[start]) && start < end) {
            start++;
        }
        // Skip non-alphanumeric characters from the end
        while (!isalnum(str[end]) && start < end) {
            end--;
        }
        // Compare characters, case-insensitive
        if (tolower(str[start]) != tolower(str[end])) {
            return 0; // Not a palindrome
        }
        start++;
        end--;
    }
    return 1; // Is a palindrome
}

int main() {
    char str[100];
    printf("Enter a string: ");
    fgets(str, sizeof(str), stdin);

    // Remove newline character added by fgets
    str[strcspn(str, "\n")] = 0;

    if (isPalindrome(str)) {
        printf("The entered string is a palindrome.\n");
    } else {
        printf("The entered string is not a palindrome.\n");
    }

    return 0;
}
```

This program, a sonnet of sorts, first asks for a string, then strips it clean,
Of spaces and signs, in case and form it we align.
It traverses both ends, comparing each pair,
Case-insensitive, in a loop that never fails to pair.

When all is done, it speaks, a message true,
Whether the string, in reverse, it did renew.
For in this world of code, where logic and art entwine,
A palindrome's beauty, we now can define.

