class UniqueIDGenerator {
  private ids: Set<number> = new Set();

  /**
   * Generates a random unique ID.
   * @returns A unique identifier, a number, in the digital night.
   */
  generateID(): number {
    let id: number;
    do {
      id = Math.floor(Math.random() * Number.MAX_SAFE_INTEGER);
