<?php
function isPerfectSquare($num) {
    // Validate input: Ensure it's a positive integer
    if (!is_numeric($num) || $num < 0 || intval($num) != $num) {
        echo "Error: Please enter a positive integer.";
        return false;
    }

    // Calculate the square root and round it to the nearest integer
    $sqrt = sqrt($num);
    $roundedSqrt = round($sqrt);

    // Check if the rounded square root squared equals the original number
    if ($roundedSqrt * $roundedSqrt == $num) {
        echo "The number {$num} is a perfect square.";
        return true;
    } else {
        echo "The number {$num} is not a perfect square.";
        return false;
    }
}

// Example usage
